import boto3
import json
import os
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
from cryptography.fernet import Fernet

# Load AWS credentials from environment variables
aws_access_key_id = os.getenv('AWS_ACCESS_KEY_ID')
aws_secret_access_key = os.getenv('AWS_SECRET_ACCESS_KEY')
aws_region = os.getenv('AWS_REGION', 'us-east-1')
sqs_queue_url = os.getenv('SQS_QUEUE_URL')

# Generate a key for encryption
encryption_key = Fernet.generate_key()
cipher = Fernet(encryption_key)

def encrypt_data(data):
    return cipher.encrypt(data.encode()).decode()

def publish_message(user_data):
    try:
        sqs_client = boto3.client(
            'sqs',
            region_name=aws_region,
            aws_access_key_id=aws_access_key_id,
            aws_secret_access_key=aws_secret_access_key
        )

        encrypted_data = {key: encrypt_data(value) for key, value in user_data.items()}
        message_body = json.dumps(encrypted_data)

        response = sqs_client.send_message(
            QueueUrl=sqs_queue_url,
            MessageBody=message_body
        )
        return response
    except (NoCredentialsError, PartialCredentialsError) as e:
        print("AWS credentials not found or incomplete:", e)
    except Exception as e:
        print("An error occurred:", e)

# Example usage
user_data = {
    'email': 'user@example.com',
    'phone': '+1234567890',
    'address': '123 Main St, Anytown, USA'
}

response = publish_message(user_data)
print(response)